import xml.etree.ElementTree as ET

def parse_xml_config(xml_file):
    tree = ET.parse(xml_file)
    root = tree.getroot()
    
    config_dict = {}
    
    for elem in root:
        tag = elem.tag
        value = elem.text
        
        if tag.endswith("_list"):
            value = [x.strip() for x in value.split(',')]
        
        config_dict[tag] = value
    
    return config_dict